-- Helper: check if a URI matches any pattern in a list
local function uri_matches(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Helper: decode a simple base64-encoded JSON token (simplified for demonstration)
local function decode_token(token)
    local cjson = require("cjson.safe")
    if not token then
        return nil, "No token provided"
    end

    -- Remove "Bearer " prefix if present
    local raw_token = token
    if string.sub(token, 1, 7) == "Bearer " then
        raw_token = string.sub(token, 8)
    end

    -- Split token into parts (header.payload.signature)
    local parts = {}
    for part in string.gmatch(raw_token, "[^%.]+") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "Invalid token format"
    end

    -- Decode the payload (base64)
    local payload_b64 = parts[2]
    -- Pad base64 if necessary
    local padding = 4 - (#payload_b64 % 4)
    if padding ~= 4 then
        payload_b64 = payload_b64 .. string.rep("=", padding)
    end

    local payload_json = ngx.decode_base64(payload_b64)
    if not payload_json then
        return nil, "Failed to decode token payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "Failed to parse token JSON: " .. (err or "unknown error")
    end

    -- Verify signature using HMAC-SHA256
    local hmac = require("resty.hmac")
    local hmac_sha256 = hmac:new(AUTH_SECRET, hmac.ALGOS.SHA256)
    if not hmac_sha256 then
        return nil, "Failed to initialize HMAC"
    end

    local sign_input = parts[1] .. "." .. parts[2]
    hmac_sha256:update(sign_input)
    local computed_sig = ngx.encode_base64(hmac_sha256:final())
    -- URL-safe base64: replace + with -, / with _, remove =
    computed_sig = string.gsub(computed_sig, "+", "-")
    computed_sig = string.gsub(computed_sig, "/", "_")
    computed_sig = string.gsub(computed_sig, "=", "")

    if computed_sig ~= parts[3] then
        return nil, "Invalid token signature"
    end

    -- Check token expiration
    if payload.exp and payload.exp < ngx.time() then
        return nil, "Token has expired"
    end

    return payload, nil
end

-- Check if a role has permission to access a given URI
local function role_has_permission(role, uri)
    local permissions = role_permissions[role]
    if not permissions then
        return false
    end

    for _, allowed_path in ipairs(permissions) do
        -- Use string matching to check if the URI starts with or contains the allowed path
        if string.find(uri, "^" .. allowed_path) then
            return true
        end
        -- Also check exact prefix match using plain string find
        if string.sub(uri, 1, #allowed_path) == allowed_path then
            return true
        end
    end

    return false
end

