        ngx.log(ngx.WARN, "Missing Authorization header for protected endpoint: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="Access to protected resource"'
        ngx.say('{"error": "Authentication required", "message": "Please provide a valid Bearer token"}')
