    if not string.match(user_role, "^[%a%d_]+$") then
        ngx.log(ngx.WARN, "Invalid role format: ", user_role)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error": "Forbidden", "message": "Invalid role format"}')
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Step 6: Check if the user's role has permission to access this URI
    -- Admin endpoints require "admin" role specifically
    if string.find(uri, "/admin", 1, true) then
        if not string.match(user_role, "^admin$") then
            ngx.log(ngx.WARN, "Non-admin user '", user_id, "' with role '", user_role,
